    CreateRecords --> RefreshAppts["Refresh Appointment Statuses<br/>(SKIPPED \u2192 PENDING/ATTENDED)"]
    RefreshAppts --> BackfillAppts["Backfill Missing Appointments<br/>from sch_appt"]
    BackfillAppts --> ExtractSvc

